52.     /// <inheritdoc />
53.     public string TimeUnitHumanize(TimeUnit timeUnit, int count, bool toWords = false)
54.     {
55.         var unit = GetUnitName(timeUnit, count != 1);
56.         return toWords ? $"{NumberToWords(count)} {unit}" : $"{count} {unit}";
57.     }
58. 
59.     private static string GetUnitName(TimeUnit timeUnit, bool plural) =>
60.         (timeUnit, plural) switch
61.         {
62.             (TimeUnit.Year, false) => "year",
63.             (TimeUnit.Year, true) => "years",
64.             (TimeUnit.Month, false) => "month",
65.             (TimeUnit.Month, true) => "months",
66.             (TimeUnit.Day, false) => "day",
67.             (TimeUnit.Day, true) => "days",
68.             (TimeUnit.Hour, false) => "hour",
69.             (TimeUnit.Hour, true) => "hours",
70.             (TimeUnit.Minute, false) => "minute",
71.             (TimeUnit.Minute, true) => "minutes",
72.             (TimeUnit.Second, false) => "second",
73.             (TimeUnit.Second, true) => "seconds",
74.             _ => plural ? timeUnit.ToString().ToLowerInvariant() + "s"
75.                         : timeUnit.ToString().ToLowerInvariant()
76.         };
77. 
