303. {
304.     /// <summary>
305.     /// Humanizes a DateTime difference relative to a base date.
306.     /// </summary>
307.     /// <param name="input">The date to humanize.</param>
308.     /// <param name="comparedTo">The reference date (typically DateTime.UtcNow).</param>
309.     /// <returns>A human-readable string representing the time difference.</returns>
310.     public string Humanize(DateTime input, DateTime comparedTo)
311.     {
312.         var difference = comparedTo - input;
313.         if (Math.Abs(difference.TotalSeconds) < 2)
314.         {
315.             return "just now";
316.         }
317. 
318.         var isFuture = difference.TotalSeconds < 0;
319.         var absDiff = difference.Duration();
320. 
321.         var result = absDiff.TotalDays switch
322.         {
323.             >= 365 => $"{(int)(absDiff.TotalDays / 365)} years",
324.             >= 31 => $"{(int)(absDiff.TotalDays / 30)} months",
325.             >= 1 => $"{(int)absDiff.TotalDays} days",
326.             _ => absDiff.TotalHours switch
327.             {
328.                 >= 1 => $"{(int)absDiff.TotalHours} hours",
329.                 _ => absDiff.TotalMinutes switch
330.                 {
331.                     >= 1 => $"{(int)absDiff.TotalMinutes} minutes",
332.                     _ => $"{(int)absDiff.TotalSeconds} seconds"
333.                 }
334.             }
335.         };
336. 
337.         return isFuture ? $"in {result}" : $"{result} ago";
338.     }
339. }
