     /// <returns>The display name or symbol for the unit.</returns>
     public string Format(string unit, bool toSymbol) =>
         toSymbol ? GetSymbol(unit) : unit;

     private static string GetSymbol(string unit) =>
         unit switch
         {
             "Byte" => "B",
             "Kilobyte" => "KB",
             "Megabyte" => "MB",
             "Gigabyte" => "GB",
             "Terabyte" => "TB",
             "Bit" => "b",
